example.code:
// At module scope — NEVER inside a component
interface ButtonProps {
  $variant?: 'primary' | 'secondary' | 'outline';
  $size?: 'sm' | 'md' | 'lg';
}

const Button = styled.button<ButtonProps>`
  display: inline-flex;
  align-items: center;
  font-weight: 500;
  border-radius: 0.375rem;
  cursor: pointer;

  ${({ $size = 'md' }) => ({
    sm: 'padding: 0.375rem 0.75rem; font-size: 0.875rem;',
    md: 'padding: 0.5rem 1rem; font-size: 1rem;',
    lg: 'padding: 0.75rem 1.5rem; font-size: 1.125rem;',
  }[$size])}

  ${({ $variant = 'primary', theme }) => $variant === 'primary' && css`
    background: ${theme.colors.primary};
    color: ${theme.colors.primaryForeground};
  `}

  &:focus-visible { outline: 2px solid ${({ theme }) => theme.colors.focus}; }
  &:disabled { opacity: 0.5; cursor: not-allowed; }
`;

// theme/theme.ts
export const lightTheme = {
  colors: {
    primary: '#3b82f6',
    primaryForeground: '#ffffff',
    background: '#ffffff',
    foreground: '#111827',
    focus: '#3b82f6',
  },
} as const;

export type Theme = typeof lightTheme;

// theme/styled.d.ts — MANDATORY for typed theme access
import 'styled-components';
declare module 'styled-components' {
  export interface DefaultTheme extends Theme {}
}

/** @jsxImportSource @emotion/react */
import { css, useTheme } from '@emotion/react';

function Card({ children, elevated = false }) {
  const theme = useTheme();
  return (
    <div css={css`
      padding: ${theme.spacing.md};
      border-radius: ${theme.radii.lg};
      background: ${theme.colors.background};
      border: 1px solid ${theme.colors.border};
      ${elevated && `box-shadow: ${theme.shadows.md}; border: none;`}
    `}>
      {children}
    </div>
  );
}
